const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextInt() {
    return parseInt(lines[idx++]);
}

function nextIntArray() {
    return lines[idx++].split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let [N, K] = nextIntArray();
    let A = nextIntArray();
    A.sort((a, b) => a - b);
    let max_taps = 0;
    for (let i = 0; i < K; i++) {
        max_taps += A[i];
    }
    console.log(max_taps);
}

